/** UsptEvlSectDao.insert */
insert into uspt_sect (
	   sect_id
	 , evl_plan_id
	 , sect_nm
	 , evl_trget_co
	 , creator_id
	 , created_dt
	 , updater_id
	 , updated_dt
) values (
	   #{sectId}
	 , #{evlPlanId}
	 , #{sectNm}
	 , #{evlTrgetCo}
	 , #{creatorId}
	 , #{createdDt}
	 , #{updaterId}
	 , #{updatedDt}
)

mapper.update:
/** UsptEvlSectDao.update */
update uspt_sect set
	   sect_nm                   = #{sectNm}
	 , evl_trget_co              = #{evlTrgetCo}
	 , updater_id                = #{updaterId}
	 , updated_dt                = #{updatedDt}
where
	sect_id = #{sectId}

mapper.delete:
		/** UsptEvlSectDao.delete */
		delete from uspt_sect
   		 where sect_id = #{sectId}
